+  private getCursorPagination(entity: Partial<T>, opts: CrudOptions) {
+    if (!opts.cursor) {
+      return null;
+    }
+    if (!opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.offset !== undefined && opts.offset !== null) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+
+    let cursor: Record<string, any>;
+    try {
+      cursor = JSON.parse(Buffer.from(opts.cursor, 'base64').toString('utf8'));
+    } catch (_) {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    if (!cursor || typeof cursor !== 'object' || Array.isArray(cursor)) {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+
+    const sortFields = this.getSortFields(opts.orderBy);
+    const expectedSort = sortFields
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (cursor.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    const idField = this.crudConfig.id_field;
+    if (!(idField in cursor)) {
+      throw new BadRequestException(`cursor is missing ${idField}`);
+    }
+    for (const { field } of sortFields) {
+      if (!(field in cursor)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+
+    return { cursor, sortFields, orderBy: this.sortFieldsToOrderBy(sortFields) };
+  }
+
+  private getSortFields(orderBy: any) {
+    const fields: { field: string; direction: 'asc' | 'desc' }[] = [];
+    for (const item of Array.isArray(orderBy) ? orderBy : [orderBy]) {
+      if (!item || typeof item !== 'object' || Array.isArray(item)) {
+        throw new BadRequestException('cursor requires a valid orderBy');
+      }
+      for (const [field, rawDirection] of Object.entries(item)) {
+        const direction = this.normalizeSortDirection(rawDirection);
+        if (!direction) {
+          throw new BadRequestException('cursor requires asc or desc orderBy');
+        }
+        fields.push({ field, direction });
+      }
+    }
+    const idField = this.crudConfig.id_field;
+    if (!fields.some(({ field }) => field === idField)) {
+      fields.push({ field: idField, direction: 'asc' });
+    }
+    return fields;
+  }
+
+  private normalizeSortDirection(direction: any): 'asc' | 'desc' | null {
+    const normalized = String(direction).toLowerCase();
+    if (normalized === 'asc' || normalized === '1') return 'asc';
+    if (normalized === 'desc' || normalized === '-1') return 'desc';
+    return null;
+  }
+
+  private sortFieldsToOrderBy(
+    sortFields: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    return sortFields.map(({ field, direction }) => ({ [field]: direction }));
+  }
+
+  private addCursorQuery(entity: Partial<T>, pagination: any): Partial<T> {
+    const { cursor, sortFields } = pagination;
+    const conditions = sortFields.map(({ field, direction }, index) => {
+      const prefix = sortFields.slice(0, index).reduce((query, previous) => {
+        query[previous.field] = cursor[previous.field];
+        return query;
+      }, {});
+      return {
+        ...prefix,
+        [field]: { [direction === 'asc' ? '$gt' : '$lt']: cursor[field] },
+      };
+    });
+    return { $and: [entity, { $or: conditions }] } as Partial<T>;
+  }
+
+  private createNextCursor(
+    entity: T,
+    sortFields: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    const cursor: Record<string, any> = {};
+    for (const { field } of sortFields) {
+      cursor[field] = entity[field];
+    }
+    cursor.__sort = sortFields
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
